import json

def get_weather(city: str, units: str = "celsius") -> str:
    # In real life: call a weather API here.
    data = {"Tokyo": 22, "Paris": 15}
    temp = data.get(city)
    if temp is None:
        return f"No data for {city}"
    if units == "fahrenheit":
        temp = round(temp * 9 / 5 + 32)
    return f"{temp} degrees, clear"

